const items = $('SelectAlertas').all();
const validItems = items.filter(i => i?.json && Object.keys(i.json).length > 0);

if (validItems.length === 0) {
  return { lista_formatada: "Você não possui alertas cadastrados no momento." };
}

// Retorna o valor ou um fallback se for null, "null", undefined ou vazio
const val = (v, fallback = null) =>
  (v === null || v === undefined || v === 'null' || v === '') ? fallback : v;

const lista = validItems.map((item, idx) => {
  const p = item.json;
  let l = `${idx + 1}. *${p.product_name}*`;

  const brand    = val(p.brand,     'Qualquer marca');
  const model    = val(p.model,     'Qualquer modelo');
  const color    = val(p.color,     'Qualquer cor');
  const price    = val(p.max_price, null);
  const features = Array.isArray(p.features) && p.features.length > 0 ? p.features : null;

  l += `\n   🏷️ Marca: ${brand}`;
  l += `\n   📱 Modelo: ${model}`;
  if (price) {
    const fmt = Number(price).toLocaleString('pt-BR', {minimumFractionDigits: 2, maximumFractionDigits: 2});
    l += `\n   💰 Preço máx: R$ ${fmt}`;
  }
  l += `\n   🎨 Cor: ${color}`;
  if (features) l += `\n   ✨ Extras: ${features.join(', ')}`;
  l += `\n   🟢 Ativo`;

  return l;
});

return { lista_formatada: lista.join('\n\n') };

const items = $('SelectAlertas2').all();
