      color:        i.json.color  || null
    }))
  }
};

const items = $('SelectAlertas_Excluir').all();
const validItems = items.filter(i => i?.json && Object.keys(i.json).length > 0);

if (validItems.length === 0) {
  return { lista_formatada: "Você não possui alertas cadastrados.\n\nSempre que precisar, é só mandar um 'Oi'! 👋" };
}

const lista = validItems.map((item, idx) => {
  const p = item.json;
  let l = `${idx + 1}. *${p.product_name}*`;
  if (p.brand || p.model)
    l += ` — ${[p.brand, p.model].filter(Boolean).join(' ')}`;
  if (p.max_price) {
    const fmt = Number(p.max_price).toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2});
    l += `\n   💰 Até R$ ${fmt}`;
  }
  if (p.color) l += `\n   🎨 ${p.color}`;
  return l;
});

return { lista_formatada: lista.join('\n\n') };

