const rawText = $('DataUser').first().json.mensagem_user || "";

const thankYouWords = ["obrigado", "obg", "obrigada", "valeu", "vlw", "agradecido", "agradecida"];
const cleanText = rawText.toLowerCase().trim();
const hasThanks = thankYouWords.some(word => cleanText.includes(word));

const status = $input.first().json.status;

let status_final = false;
if (["resposta_menu", "menu"].includes(status) && hasThanks) {
    status_final = true;
}

return {
    json: {
        contains_thanks: status_final
    }
};

const items = $input.all();
const validItems = items.filter(i => i.json && Object.keys(i.json).length > 0);
const count = validItems.length;
const MAX_ALERTS = 8;

const userName = $('Get_User').first().json.name || 'você';

let menu = `Olá, ${userName}! 😊 O que deseja fazer?\n\n`;
menu += `1️⃣ Cadastrar novo alerta`;

if (count > 0) {
  menu += `\n2️⃣ Listar seus alertas (${count} ativo${count !== 1 ? 's' : ''})`;
  menu += `\n3️⃣ Excluir um alerta`;
} else {
  menu += `\n\n_Você ainda não tem alertas cadastrados._`;
}
menu += `\n4️⃣ Cancelar`;

if (count >= MAX_ALERTS) {
  menu += `\n\n⚠️ Limite de ${MAX_ALERTS} alertas atingido. Exclua um para cadastrar novo.`;
}

return { json: { menu_text: menu } };

return {
  json: {
    menu_text:
      `O que deseja fazer?\n\n` +
      `1️⃣ Cadastrar novo alerta\n\n` +
      `_Você ainda não tem alertas cadastrados._\n` +
      `4️⃣ Cancelar`
  }
};

